from functools import wraps
import agno

def pii_safe_agent():
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            result = func(*args, **kwargs)
            # Filter PII from all output types
            if isinstance(result, str):
                return safe_agent_output(result)
            elif isinstance(result, dict):
                return {k: safe_agent_output(str(v)) for k, v in result.items()}
            return result
        return wrapper
    return decorator

@pii_safe_agent()
def run_agno_agent(prompt: str):
    agent = agno.Agent(name='pii-safe-agent')
    return agent.run(prompt)

# Usage
result = run_agno_agent('Extract contact from: John, 555-123-4567')
print(result)

class PiiSafeMemory:
    def __init__(self):
        self.memory = []
        self.pii_filter = create_pii_filter()

    def add(self, content: str):
        sanitized = self.pii_filter(content)
        self.memory.append({
            'original_hash': hash(content),
            'sanitized': sanitized,
            'timestamp': agno.utils.now()
        })

    def get(self, n: int = 10) -> list:
        return [m['sanitized'] for m in self.memory[-n:]]

# Agno agent integration
class SafeAgent(agno.Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.memory = PiiSafeMemory()

    def run(self, prompt):
        self.memory.add(prompt)
        result = super().run(prompt)
        self.memory.add(str(result))
